Code:
public int countClumps(int[] nums) {
    int count = 0;
    int i = 0;
    while (i < nums.length - 1) {
        if (nums[i] == nums[i + 1]) {
            int j = i;
            while (j < nums.length - 1 && nums[j] == nums[j + 1]) {
                j++;
            }
            count++;
            i = j;
        } else {
            i++;
        }
    }
    return count;
}

