public String atFirst(String str) {
    int length = Math.min(2, str.length());
    return str.substring(0, length) + "@".repeat(2 - length);
}

public int roundSum(int a, int b, int c) {
    a = round10(a);
    b = round10(b);
    c = round10(c);
    return a + b + c;
}

public int round10(int num) {
    int lastDigit = num % 10;
    if (lastDigit >= 5) {
        num += 10 - lastDigit;
    } else {
        num -= lastDigit;
    }
    return num - num % 10;
}

